joi_to_register.script:
phase := 0
if (phase == 0) {
wait until((#AirQualitySensor #ParkingLot).airQualitySensor_carbonDioxide > 880)
    phase = 1
    (#Speaker #ParkingLot).speaker_speak("CO2 level danger")
}
else {
(#Speaker #ParkingLot).speaker_speak("CO2 level danger")
}

t1 = all(#TemperatureSensor #WineCellar).temperatureSensor_temperature
delay(10 MIN)
t2 = all(#TemperatureSensor #WineCellar).temperatureSensor_temperature
diff = t2 - t1
if (diff < 0) {
diff = t1 - t2
}
if (diff >= 1) {
(#Speaker).speaker_speak("The wine cellar temperature has changed rapidly")
}

hold_ticks := 0
if ((#PresenceSensor #Presence).presenceSensor_presence == true) {
hold_ticks = hold_ticks + 1
    if (hold_ticks >= 1200) {
(#Plug #Switch #Projector).switch_on()
        break
}
}
else {
hold_ticks = 0
}

